var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"유다, 이렇게만 하면 나나하라 당주가 혼자 이곳에 오는 게 확실하겠지?","JPN":"ユダ、こうすれば確かに七原家当主が一人でこちらへ来るのだろうな？","ENG":"Are you sure Lady Nanahara will come alone, Judas?","TWN":"尤達，你確定只要這麼做，七原堂主就會自投羅網嗎？"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"걱정마시오. 레노어의 예견은 틀린 적이 없으니.","JPN":"安心しろ。レノアの予言は外れたことがない。","ENG":"Do not worry. Lenore’s predictions are never wrong.","TWN":"放心，蕾諾雅的預言不會錯的。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"진전없이 싸우는 꼴을 구경만 하는 것도 지겹군.","JPN":"何の進展もなく戦っている様子を見ているのもうんざりするな。","ENG":"It bores me to see such a dull battle.","TWN":"我已經看膩無謂的打殺。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"동감이오.","JPN":"同感だ。","ENG":"Agreed.","TWN":"我也認同。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"이렇게 많은 피실험체가 모여 있으니, 적신인자를 시험해보는 것도 나쁘지 않겠지.","JPN":"これだけ多くの被実験体が集まっているのだ、クリムゾン・ファクターを試してみるのも悪くない。","ENG":"Since there are so many test subjects gathered up, why not test out the embedded factor?","TWN":"這裡有這麼多非實驗體，不如來實驗一下適神因子吧？"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"적신인자? 이런 곳에서 대체 뭘 할 셈인가?","JPN":"クリムゾン・ファクター？　こんなところでいったい何をする気なんだ？","ENG":"The embedded factor? What do you plan on doing in a place like this?","TWN":"適神因子？你打算在這裡做什麼？"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"이 약물은 일전에 만났던 환상종 자손의 피를 가공한 것이오.","JPN":"この薬物はこの前出会った幻想種の子孫の血を加工したものだ。","ENG":"This is processed blood from a Bygone descendant we met earlier.","TWN":"不久前我們有遇到一個夢幻類，這是用她的血液加工而成的藥。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"환상종……?","JPN":"幻想種……？","ENG":"A Bygone...?","TWN":"夢幻類……？"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"설마 고르디우스의 그 계집을 만난 건가?","JPN":"まさかゴルディウスのあの女に会ったのか？","ENG":"You met the Gordias girl.","TWN":"你們遇到那個戈爾迪亞的丫頭嗎？"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그렇소.","JPN":"そうだ。","ENG":"Correct.","TWN":"是的。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그 여인은 명부신이라 불리는 환상종의 직계 혈통.","JPN":"あの女は冥府の神と呼ばれる幻想種の直系子孫。","ENG":"She is the direct descendant of Bygone blood, otherwise known as the Nether God.","TWN":"她身上流的血，是稱為冥府神這個夢幻類的血。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그대가 가진 역신의 피만큼은 아니더라도 나나하라 후손들의 잠재력을 끌어내기엔 충분하겠지.","JPN":"そなたが持っている疫病神の血ほどではないが、七原家の子孫の潜在力を引き出すには十分だろう。","ENG":"Although not as powerful as the Plague God blood you acquired, it is enough to pull out the potential of the Nanahara heritage.","TWN":"就算不是你手上的瘟神血液，但應該也足以激發出七原後裔的潛能吧？"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"흥, 내가 가진 역신의 피에 대체제 같은 건 없어.","JPN":"ふん、私の持っている疫病神の血に代わりなどない。","ENG":"Hmph. There is no such thing as a substitute for Plague God blood.","TWN":"哼，沒有任何東西可以代替我手上的瘟神血液。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"그런 방식으로 원하는 결과를 얻진 못할 텐데?","JPN":"そのような方法では望ましい結果は出せないはずだが？","ENG":"You will not get anywhere with something like that.","TWN":"這樣是無法達到你想要的結果的。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"상관없소. 이 계획이 성공하건 실패하건, 우리가 바라는 결과로 이어질 테니까.","JPN":"構わない。この計画が成功しようがしまいが、我らの望んでいた結果に繋がるだろうからな。","ENG":"It does not matter. Whether it succeeds or not, it will lead us to the desired outcome.","TWN":"無所謂，無論這個計畫成功或失敗，都會導向我們想要的結果。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_A","text":{"KOREA":"젠장, 대체 어디서 이렇게 많은 병력이 나타난 거야?","JPN":"くそ、いったいどこからこれだけの兵力が現れたんだ？","ENG":"Damn it, just where did they all come from?","TWN":"可惡，這些人到底都是從哪冒出來的？"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_A","text":{"KOREA":"애초에 차량을 타고 탈출할 작정이었다면 왜 매복이 있는 거지?","JPN":"そもそも車両に乗って脱出するつもりだったらなんで待ち伏せしてるんだよ。","ENG":"Why are there ambush forces if he was going to flee in the first place?","TWN":"要是他一開始就打算搭車逃亡，那怎麼會有埋伏？"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_B","text":{"KOREA":"이봐! 생각은 나중에 정리하고 쏘기나 해!","JPN":"おい！　考えは後でしろ、今は撃て！","ENG":"Hey! Stop thinking and shoot!","TWN":"喂！這些之後再想吧，快開槍！"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"}}}}]`);export{e as default};